    private fun postToJs(event: String, payload: JSONObject) {
        val msg = JSONObject()
        msg.put("event", event)
        msg.put("payload", payload)
        val js = "window.dispatchEvent(new CustomEvent('native', { detail: ${msg.toString()} }));"
        webView.post {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                webView.evaluateJavascript(js, null)
            } else {
                webView.loadUrl("javascript:$js")
            }
        }
    }

    private fun respond(callbackId: String?, ok: Boolean, data: JSONObject?) {
        val payload = JSONObject()
        payload.put("ok", ok)
        if (callbackId != null) payload.put("callbackId", callbackId)
        if (data != null) payload.put("data", data)
        postToJs("response", payload)
    }

    @JavascriptInterface
    fun ping(): String = "pong"

